def is_rate_limited(user_id: str, limit: int = 100, window: int = 60) -> bool: key = f"ratelimit:{user_id}" now = time.time()
pipe = r.pipeline() pipe.zremrangebyscore(key, 0, now - window) # evict old requests pipe.zadd(key, {str(now): now}) # record this request pipe.zcard(key) # count window pipe.expire(key, window) # auto-cleanup results = pipe.execute()
return results[2] > limit

# Pub/Sub for real-time messaging (at-most-once, ephemeral)
def publisher():
    r.publish("notifications", json.dumps({
        "type": "order_update",
        "order_id": "123",
        "status": "shipped"
    }))

def subscriber():
    pubsub = r.pubsub()
    pubsub.subscribe("notifications")
    for message in pubsub.listen():
        if message["type"] == "message":
            data = json.loads(message["data"])
            handle_notification(data)
